191: func newNestedValueValidation(s *apiextensions.JSONSchemaProps) (*NestedValueValidation, error) {
192: 	if s == nil {
193: 		return nil, nil
194: 	}
195: 
196: 	if err := validateUnsupportedFields(s); err != nil {
197: 		return nil, err
198: 	}
199: 
200: 	vv, err := newValueValidation(s)
201: 	if err != nil {
202: 		return nil, err
203: 	}
204: 
205: 	g, err := newGenerics(s)
206: 	if err != nil {
207: 		return nil, err
208: 	}
209: 
210: 	x, err := newExtensions(s)
211: 	if err != nil {
212: 		return nil, err
213: 	}
214: 
215: 	vx, err := newValidationExtensions(s)
216: 	if err != nil {
217: 		return nil, err
218: 	}
219: 
220: 	v := &NestedValueValidation{
221: 		ValueValidation:      *vv,
222: 		ValidationExtensions: *vx,
223: 		ForbiddenGenerics:    *g,
224: 		ForbiddenExtensions:  *x,
225: 	}
226: 
227: 	if s.Items != nil {
228: 		if len(s.Items.JSONSchemas) > 0 {
229: 			// we validate that it is not an array
230: 			return nil, fmt.Errorf("OpenAPIV3Schema 'items' must be a schema, but is an array")
231: 		}
232: 		nvv, err := newNestedValueValidation(s.Items.Schema)
233: 		if err != nil {
234: 			return nil, err
235: 		}
236: 		v.Items = nvv
237: 	}
238: 	if s.Properties != nil {
239: 		v.Properties = make(map[string]NestedValueValidation, len(s.Properties))
240: 		for k, x := range s.Properties {
241: 			nvv, err := newNestedValueValidation(&x)
242: 			if err != nil {
243: 				return nil, err
244: 			}
245: 			v.Properties[k] = *nvv
246: 		}
247: 	}
248: 	if s.AdditionalProperties != nil {
249: 		if s.AdditionalProperties.Schema != nil {
250: 			additionalPropertiesSchema, err := newNestedValueValidation(s.AdditionalProperties.Schema)
251: 			if err != nil {
252: 				return nil, err
253: 			}
254: 			v.AdditionalProperties = additionalPropertiesSchema
255: 		} else if s.AdditionalProperties.Allows {
256: 			v.AdditionalProperties = &NestedValueValidation{}
257: 		}
258: 
259: 	}
260: 
261: 	return v, nil
262: }
263: 
264: func newExtensions(s *apiextensions.JSONSchemaProps) (*Extensions, error) {
265: 	if s == nil {
266: 		return nil, nil
267: 	}
268: 
269: 	ret := &Extensions{
270: 		XEmbeddedResource: s.XEmbeddedResource,
271: 		XIntOrString:      s.XIntOrString,
272: 		XListMapKeys:      s.XListMapKeys,
273: 		XListType:         s.XListType,
274: 		XMapType:          s.XMapType,
275: 	}
276: 
277: 	if s.XPreserveUnknownFields != nil {
278: 		if !*s.XPreserveUnknownFields {
279: 			return nil, fmt.Errorf("internal error: 'x-kubernetes-preserve-unknown-fields' must be true or undefined")
280: 		}
281: 		ret.XPreserveUnknownFields = true
282: 	}
283: 
284: 	return ret, nil
285: }
286: 
287: func newValidationExtensions(s *apiextensions.JSONSchemaProps) (*ValidationExtensions, error) {
288: 	if s == nil {
289: 		return nil, nil
290: 	}
291: 
292: 	ret := &ValidationExtensions{}
293: 	if err := apiextensionsv1.Convert_apiextensions_ValidationRules_To_v1_ValidationRules(&s.XValidations, &ret.XValidations, nil); err != nil {
294: 		return nil, err
295: 	}
296: 
297: 	return ret, nil
298: }
